#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2000005;
const double eps=1e-10;
int n,siz[N];
double a[N],ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=0;i<(1<<n);i++)
	{
		cin>>a[i];
	}
	for(int k=1;k<(1<<n);k*=2)//         1---.---.---.---.---.---1
	{//                                  1-------1-------1-------1
		for(int i=0;i<(1<<n);i+=(k*2))// 1---,---.---,---.---,---1
		{
			for(int j=i;j<i+k;j++)
			{
				a[j+k]+=a[j];
			}
		}
	}
	for(int i=1;i<(1<<n);i++)
	{
		siz[i]=(siz[i/2]+(i%2));
	}
	for(int i=1;i<(1<<n);i++)
	{
		int mask=((1<<n)-1)^i;
		if(1-a[mask]<eps)
		{
			cout<<"INF\n";
			return 0;
		}
		double tmp=1/(1-a[mask]);
		if(siz[i]%2)
		{
			ans+=tmp;
		}
		else ans-=tmp;
	}
	cout<<fixed<<setprecision(10)<<ans;
	return 0;
}
